import{c as h,S as n,j as a,m as l}from"./chunks/framework.8aa1YH_s.js";const s=JSON.parse('{"title":"Hỏi đáp (Admin)","description":"","frontmatter":{},"headers":[],"relativePath":"admin/hoi-dap.md","filePath":"admin/hoi-dap.md","lastUpdated":0}'),t={name:"admin/hoi-dap.md"};function o(c,i,r,g,e,u){return n(),a("div",null,[...i[0]||(i[0]=[l('<h1 id="hoi-đap-admin" tabindex="-1">Hỏi đáp (Admin) <a class="header-anchor" href="#hoi-đap-admin" aria-label="Permalink to “Hỏi đáp (Admin)”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/admin/reply</code></p><p>Trang Hỏi đáp ở khu vực Admin tập hợp <strong>toàn bộ câu hỏi</strong> mà học viên gửi (cho khóa học / bài giảng / câu hỏi đề thi cụ thể). Admin có thể:</p><ul><li>Xem mọi câu hỏi đang chờ giáo viên trả lời.</li><li>Chuyển câu hỏi sang đúng giáo viên.</li><li>Trả lời thay khi cần.</li><li>Kiểm duyệt / xóa nội dung không phù hợp.</li></ul><h2 id="danh-sach-cau-hoi" tabindex="-1">Danh sách câu hỏi <a class="header-anchor" href="#danh-sach-cau-hoi" aria-label="Permalink to “Danh sách câu hỏi”">​</a></h2><p>Cột chính:</p><ul><li>Học viên hỏi (tên, SĐT)</li><li>Tiêu đề / nội dung tóm tắt</li><li>Liên kết tới (Khóa học / Bài giảng / Câu hỏi đề thi cụ thể)</li><li>Giáo viên được giao trả lời</li><li>Trạng thái (Chưa trả lời / Đã trả lời / Đã đóng / Ẩn)</li><li>Thời gian gửi</li><li>Số lượt phản hồi</li></ul><h2 id="bo-loc" tabindex="-1">Bộ lọc <a class="header-anchor" href="#bo-loc" aria-label="Permalink to “Bộ lọc”">​</a></h2><ul><li>Theo trạng thái</li><li>Theo giáo viên được giao</li><li>Theo khóa học / khung chương trình</li><li>Theo khoảng thời gian</li><li>Tìm kiếm trong nội dung</li></ul><h2 id="mo-chi-tiet-tra-loi" tabindex="-1">Mở chi tiết &amp; trả lời <a class="header-anchor" href="#mo-chi-tiet-tra-loi" aria-label="Permalink to “Mở chi tiết &amp; trả lời”">​</a></h2><ol><li>Bấm vào dòng câu hỏi → mở luồng hội thoại.</li><li>Đọc nội dung học viên hỏi (kèm hình ảnh, file đính kèm nếu có).</li><li>Gõ phản hồi: <ul><li>Có rich text: chèn ảnh, công thức (LaTeX), code.</li><li>Có thể đính kèm file.</li></ul></li><li>Bấm <strong>Gửi</strong>.</li><li>Học viên nhận thông báo (push / email) và có thể tiếp tục hỏi.</li></ol><h2 id="chuyen-cau-hoi" tabindex="-1">Chuyển câu hỏi <a class="header-anchor" href="#chuyen-cau-hoi" aria-label="Permalink to “Chuyển câu hỏi”">​</a></h2><p>Nếu câu hỏi đến không đúng giáo viên (hoặc giáo viên đang bận):</p><ol><li>Mở chi tiết → bấm <strong>Chuyển</strong> → chọn giáo viên mới.</li><li>(Tùy chọn) thêm ghi chú nội bộ.</li><li>Giáo viên mới sẽ thấy câu hỏi trong hộp thư của họ.</li></ol><h2 id="đong-ket-thuc-cau-hoi" tabindex="-1">Đóng / Kết thúc câu hỏi <a class="header-anchor" href="#đong-ket-thuc-cau-hoi" aria-label="Permalink to “Đóng / Kết thúc câu hỏi”">​</a></h2><ul><li>Khi câu hỏi đã giải đáp xong, bấm <strong>Đóng</strong>. Học viên vẫn xem lại được.</li><li>Sau khi đóng, không cho nhập thêm phản hồi (trừ khi mở lại).</li></ul><h2 id="an-xoa-noi-dung-khong-phu-hop" tabindex="-1">Ẩn / xóa nội dung không phù hợp <a class="header-anchor" href="#an-xoa-noi-dung-khong-phu-hop" aria-label="Permalink to “Ẩn / xóa nội dung không phù hợp”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Đối với nội dung spam, ngôn từ không phù hợp:</p><ul><li><strong>Ẩn</strong> sẽ giấu khỏi học viên khác nhưng giữ lại cho admin xem.</li><li><strong>Xóa</strong> vĩnh viễn (chỉ nên dùng khi chắc chắn).</li></ul></div><h2 id="theo-doi-sla-tra-loi" tabindex="-1">Theo dõi SLA trả lời <a class="header-anchor" href="#theo-doi-sla-tra-loi" aria-label="Permalink to “Theo dõi SLA trả lời”">​</a></h2><ul><li>Cột <strong>Thời gian gửi</strong> và <strong>Trạng thái</strong> giúp đo nhanh: câu hỏi nào để quá lâu chưa trả lời.</li><li>Có thể đặt SLA nội bộ (vd: phản hồi trong 24 giờ làm việc).</li><li>Báo cáo trễ → liên hệ giáo viên / chuyển admin trả lời.</li></ul><h2 id="bao-cao" tabindex="-1">Báo cáo <a class="header-anchor" href="#bao-cao" aria-label="Permalink to “Báo cáo”">​</a></h2><ul><li>Số câu hỏi mới / tuần.</li><li>Top khóa nhận nhiều câu hỏi (có thể là chuyên đề khó, cần bổ sung tài liệu).</li><li>Top giáo viên trả lời nhiều / nhanh.</li><li>Câu hỏi tồn đọng quá X ngày.</li></ul><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Học viên hỏi câu hỏi không liên quan đến khóa, có nên xóa không?</strong> → Tốt hơn là <strong>chuyển sang bộ phận CSKH</strong> (nếu có chức năng) hoặc trả lời chung hướng dẫn họ về kênh khác.</p><p><strong>Giáo viên không trả lời kịp.</strong> → Admin có thể trả lời thay, hoặc nhắc trực tiếp giáo viên qua thông báo nội bộ.</p><p><strong>Có thể duyệt câu hỏi trước khi học viên khác xem được không?</strong> → Có. Bật chế độ <strong>Kiểm duyệt</strong> ở cấu hình khóa. Câu hỏi chỉ hiển thị công khai sau khi admin / giáo viên duyệt.</p>',26)])])}const p=h(t,[["render",o]]);export{s as __pageData,p as default};
